import { Component, ErrorInfo, ReactNode } from "react";
import * as Sentry from "@sentry/browser";
import {t} from "ftc-common/i18n";

interface Props {
    children?: ReactNode;
}

interface State {
    hasError: boolean;
    error?: Error
}

export default class ErrorBoundary extends Component<Props, State> {
    constructor(props: Props) {
        super(props);
        this.state = { hasError: false };
    }

    static getDerivedStateFromError(error: Error): State {
        // Update state so the next render will show the fallback UI.
        return { hasError: true, error };
    }

    componentDidCatch(error: Error, info: ErrorInfo) {
        Sentry.captureException(error)
    }

    resetError() {
        this.setState({ hasError: false })
    }

    render() {
        if (this.state.hasError) {
            // You can render any custom fallback UI
            return <div>
                <p>
                    An error occurred. Please <a href="/feedback/" target="_blank">contact support</a> if clicking "Try
                    again" or refreshing the page does not
                    resolve the issue.
                </p>
                <details style={{ whiteSpace: 'pre-wrap', margin: '10px' }}>
                    {this.state.error && this.state.error.toString()}
                </details>
                <button onClick={this.resetError} className={"btn btn-secondary"}>{t`Try again`}</button>
            </div>
        }

        return this.props.children;
    }
}